      "id": "introducing-google-antigravity-2-0",
      "title": "Introducing Google Antigravity 2.0",
      "source": "DeepMind",
      "category": "",
      "date_iso": "2026-05-17",
      "date_display": "May 17, 2026",
      "link": "https://deepmind.google/blog/introducing-google-antigravity-2-0/",
